const generateRooms = (floor, start, end) => {
    let rooms = [];
    for (let i = start; i <= end; i++) {
        rooms.push({
            id: i,
            floor: floor,
            status: 'unchecked', // unchecked, checked, dnd
            lastCleaning: new Date().toLocaleDateString(),
            notes: '',
            inventory: [
                { name: 'Кола', count: 2, expiry: '2026-07-01' },
                { name: 'Пиво', count: 2, expiry: '2026-08-15' },
                { name: 'Редбулл', count: 1, expiry: '2026-09-10' },
                { name: 'Вино красное', count: 1, expiry: null },
                { name: 'Вино белое', count: 1, expiry: null },
                { name: 'Водка', count: 1, expiry: '2027-01-01' },
                { name: 'Виски Джеймсон', count: 1, expiry: '2027-06-01' },
                { name: 'Виски Чивас', count: 1, expiry: '2027-06-01' },
                { name: 'Фисташки', count: 1, expiry: '2026-05-20' },
                { name: 'Орбит', count: 1, expiry: '2026-12-01' },
                { name: 'M&Ms', count: 1, expiry: '2026-08-15' },
                { name: 'Сникерс', count: 1, expiry: '2026-07-10' }
            ]
        });
    }
    return rooms;
};

export const ALL_ROOMS = [
    ...generateRooms(3, 301, 348),
    ...generateRooms(4, 401, 471),
    ...generateRooms(5, 501, 555)
];
